import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface RecentAlert {
  time: string;
  camera: string;
  motionDetected: boolean;
}

interface SecurityCameraData {
  activeCameras: number;
  recentAlerts: RecentAlert[];
  status: string;
}

export default function Widget() {
  const { activeCameras, recentAlerts, status } = response.data as SecurityCameraData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 400,
        bgcolor: theme === 'dark' ? '#1F2937' : '#FFFFFF',
        color: theme === 'dark' ? '#F8FAFC' : '#1F2937',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: primaryColor }}>
              Home Secure
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Active Cameras: {activeCameras}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Recent Alerts
            </Typography>
            <Stack spacing={0.5}>
              {recentAlerts.slice(0, 3).map((alert, index) => (
                <Chip
                  key={index}
                  label={`${alert.camera}: ${alert.motionDetected ? 'Motion Detected' : 'No Motion'}`}
                  icon={<Info sx={{ color: accentColor }} />}
                  sx={{
                    fontSize: '11px',
                    color: alert.motionDetected ? accentColor : 'text.secondary',
                    bgcolor: theme === 'dark' ? '#374151' : '#F3F4F6',
                    px: 1,
                    py: 0.5,
                  }}
                />
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Status: {status}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
